export const PERFUMES = RAW.map((d, idx) => ({
  id: idx, name: d[0], brand: BRAND_NAMES[d[1]], year: d[2], gender: GM[d[3]],
  concentration: d[4], family: d[5], priceLow: d[6], priceHigh: d[7],
  notes: [...d[8].split("|").filter(Boolean).map(n => ({ name: n, position: "top", strength: 70 + (idx * 7 + n.length * 3) % 25 })),
         ...d[9].split("|").filter(Boolean).map(n => ({ name: n, position: "heart", strength: 55 + (idx * 5 + n.length * 7) % 30 })),
         ...d[10].split("|").filter(Boolean).map(n => ({ name: n, position: "base", strength: 50 + (idx * 3 + n.length * 11) % 35 }))],
  accords: d[11].split("|").filter(Boolean).map((a, i) => ({ name: a, strength: Math.max(30, 90 - i * 12 + (a.length * 3) % 8) })),
  rating: +((38 + (idx * 7) % 7) / 10).toFixed(1),
  genderVotes: { feminine: 30 + (idx * 13) % 40, masculine: 10 + (idx * 7) % 30, unisex: 20 + (idx * 11) % 40 },
}));
export const FAMILIES = [...new Set(PERFUMES.map(p => p.family))].sort();
export const ALL_NOTES = (() => { const m = {}; PERFUMES.forEach(p => p.notes.forEach(n => { if (!m[n.name]) m[n.name] = { name: n.name, count: 0 }; m[n.name].count++; })); return Object.values(m).sort((a, b) => b.count - a.count); })();
export const BRANDS = (() => { const m = {}; PERFUMES.forEach(p => { if (!m[p.brand]) m[p.brand] = { name: p.brand, type: BRAND_TYPES[p.brand] || "Unknown", count: 0, perfumes: [] }; m[p.brand].count++; m[p.brand].perfumes.push(p); }); return Object.values(m).sort((a, b) => b.count - a.count); })();
